import React from 'react';
import PageLogo from '../Logo/GnuLinuxLogo.svg';
import HeaderInfoBackgroundImage from '../Background/HeaderInfoBackgroundImage.jpg';
import HeaderInfoGitHubLogo from '../Logo/GitHubLogo.svg';

import '../HeaderInfo.css';

class HeaderInfo extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      domainLogo: props.domainLogo || PageLogo,
      currentPageName: props.currentPageName || '',
      backgroundImage: props.backgroundImage || HeaderInfoBackgroundImage,
      githubLogo: props.githubLogo || HeaderInfoGitHubLogo,
      githubURL: props.githubURL || "www.github.com",
      githubPagesURL: props.githubPagesURL || "www.github.com",
      domainName: props.domainName || "www.unix69.githubio.com",
      pageName: props.pageName || "Unix69",
      headerTitleInfoClass: props.headerTitleInfoClass || "header-title-info",
      headerInfoBackgroundImageClass: props.headerInfoBackgroundImageClass || "header-title-info-background-image",
      headerInfoDomainInfoClass: props.headerTitleInfoClass || "header-title-info-domain-info",
      headerInfoDomainUrlClass: props.headerInfoDomainUrlClass || "header-title-info-domain-url",
      headerInfoDomainLogoClass: props.headerInfoDomainLogoClass || "header-title-info-domain-logo",
      headerSubInfoCurrentPageClass: props.headerSubInfoCurrentPageClass ||  "header-main-info-current-page",
      headerSubInfoSpaceClass: props.headerSubInfoSpaceClass || "header-main-info-space",
      headerSubInfoGitHubInfoClass: props.headerSubInfoGitHubInfoClass || "header-main-info-github-info",
      headerSubInfoGitHubUrlClass: props.headerSubInfoGitHubUrlClass || "header-main-info-github-url",
      headerSubInfoGitHubPagesUrlClass: props.headerSubInfoGitHubPagesUrlClass || "header-main-info-github-pages-url",
      headerSubInfoGitHubLogoClass: props.headerSubInfoGitHubLogoClass || "header-main-info-github-logo",
      headerSubInfoGitHubPagesLogoClass: props.headerSubInfoGitHubPagesLogoClass || "header-main-info-github-pages-logo"
    };
  }

  render() {
    return (<section>
              <div class={this.state.headerTitleInfoClass}>
                <div class={this.state.headerInfoDomainInfoClass}>
                  <img src={this.state.domainLogo} alt="Domain Logo" className={this.state.headerInfoDomainLogoClass}/>
                  <a href={this.state.domainName} class={this.state.headerInfoDomainUrlClass}>{this.state.pageName}</a>
                </div>
              </div>


              <div class={this.state.headerSubInfoClass}>
                <div class={this.state.headerInfoCurrentPageClass}>{this.state.currentPageName}</div>
                <div class={this.state.headerInfoSpaceClass}/>
                <div class={this.state.headerInfoGitHubInfoClass}>                 
                  <a href={this.state.githubURL} class={this.state.headerInfoGitHubUrlClass}/>
                  <img src={this.state.githubLogo} alt="GitHub Logo" class={this.state.headerInfoGitHubLogoClass}/>
                  <a href={this.state.githubPagesURL} class={this.state.headerInfoGitHubPagesUrlClass}>{this.state.githubPagesURL}</a>
                </div>
              </div>




            </section>
    );
  }
}

export default HeaderInfo;
